#include <stdio.h>
int main() {
    int N, M, L;
    scanf("%d %d", &N, &M);
    int A[N][M];
    for (int i = 0; i < N; i++) {
        for (int j = 0; j < M; j++) {
            scanf("%d", &A[i][j]);
        }
    }
    scanf("%d", &L);
    int E1 = 0, E2 = 0;
    int ik, jk;
    int ik_jk[L][2];
    for (int i = 0; i < L; i++) {
        scanf("%d %d", &ik, &jk);
        ik_jk[i][0] = ik;
        ik_jk[i][1] = jk;
    }
    for (int i = 0; i < L; i++) {
        ik = ik_jk[i][0];
        jk = ik_jk[i][1];
        if (ik <= N && jk <= M) {
            E1 += A[ik-1][jk-1];
        } else {
            E1 = -1;
            break;
        }
    }
    for (int i = 0; i < L; i++) {
        ik = ik_jk[i][0];
        jk = ik_jk[i][1];
        if (jk <= N && ik <= M) {
            E2 += A[jk-1][ik-1];
        } else {
            E2 = -1;
            break;
        }
    }
    printf("%d\n", (E1 > E2) ? E1 : E2);
    return 0;
}

