import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int N = sc.nextInt();
        int M = sc.nextInt();
        int[][] A = new int[N][M];
        for (int i = 0; i < N; i++) {
            for (int j = 0; j < M; j++) {
                A[i][j] = sc.nextInt();
            }
        }
        int L = sc.nextInt();
        int E1 = 0, E2 = 0;
        int ik, jk;
        int[][] ik_jk = new int[L][2];
        for (int i = 0; i < L; i++) {
            ik = sc.nextInt();
            jk = sc.nextInt();
            ik_jk[i][0] = ik;
            ik_jk[i][1] = jk;
        }
        for (int i = 0; i < L; i++) {
            ik = ik_jk[i][0];
            jk = ik_jk[i][1];
            if (ik <= N && jk <= M) {
                E1 += A[ik-1][jk-1];
            } else {
                E1 = -1;
                break;
            }
        }
        for (int i = 0; i < L; i++) {
            ik = ik_jk[i][0];
            jk = ik_jk[i][1];
            if (jk <= N && ik <= M) {
                E2 += A[jk-1][ik-1];
            } else {
                E2 = -1;
                break;
            }
        }
        System.out.println(Math.max(E1, E2));
    }
}

